def gen(rng, size):
    n = max(1, min(size, 100000))
    s = ''.join(str(rng.randint(1, 9)) for _ in range(n))
    if rng.random() < 0.5:
        k = rng.randint(1, 20)
    else:
        k = rng.randint(1, 1000000000)
    return [s, k]

