class Solution:
    def minimumPartition(self, s, k):
        n = len(s)
        i = 0
        count = 0
        while i < n:
            d = int(s[i])
            if d > k:
                return -1
            length = 1
            while i + length + 1 <= n and int(s[i:i + length + 1]) <= k:
                length += 1
            count += 1
            i += length
        return count

