class Solution:
    def minimumPartition(self, s, k):
        count = 1
        cur = 0
        for ch in s:
            d = int(ch)
            if d > k:
                return -1
            nxt = cur * 10 + d
            if nxt > k:
                count += 1
                cur = d
            else:
                cur = nxt
        return count

