var minimumPartition = function(s, k) {
    let count = 1;
    let cur = 0;
    for (const ch of s) {
        const d = Number(ch);
        if (d > k) return -1;
        const nxt = cur * 10 + d;
        if (nxt > k) {
            count++;
            cur = d;
        } else {
            cur = nxt;
        }
    }
    return count;
};
